const handleSend = async () => {
    if (!input.trim()) return;

    // 1. Add User Message
    const userMsg = { text: input, isBot: false };
    setMessages((prev) => [...prev, userMsg]);
    setInput("");
    setIsThinking(true);

    try {
      // 🚨 DEBUG: Log the key to make sure it's being read (Remove this later!)
      console.log("Using API Key:", API_KEY); 

      const genAI = new GoogleGenerativeAI(API_KEY);
      const model = genAI.getGenerativeModel({ model: "gemini-1.5-flash" });

      console.log("Sending request to Google..."); // 🚨 DEBUG

      const result = await model.generateContent(input);
      const response = await result.response;
      const text = response.text();

      console.log("Received response:", text); // 🚨 DEBUG

      setIsThinking(false);
      setMessages((prev) => [...prev, { text: text, isBot: true }]);
      
    } catch (error) {
      // 🚨 THIS IS THE IMPORTANT PART
      console.error("🔥 FULL ERROR DETAILS:", error); 
      
      setIsThinking(false);
      setMessages((prev) => [...prev, { text: `Error: ${error.message}`, isBot: true }]);
    }
  };
